	(2988, 1042, 857, 1042, 1314, 1, 'How to measure progress in psychedelic integration with Tomas Frymann', 'how-to-measure-progress-in-psychedelic-integration-with-tomas-frymann', '<div class=\"content-row uk-position-relative uk-flex with-redo row-columns-1-3 padding-none has-section-width-uk-container\" style=\"background-color: rgb(255, 255, 255);\">\n    <div class=\"uk-container\">\n        <div class=\"uk-grid\">\n            <div class=\"uk-width-1-3@m uk-position-relative\">\n                <div class=\"grid-inner\">\n                    <div class=\"uk-sortable\">\n                                            <div class=\"content-block\">\n                            <div class=\"content-block-inner\"><figure class=\"redactor-component-active\" tabindex=\"-1\"><span class=\"redactor-component-caret\">﻿</span><iframe style=\"border-radius:12px\" src=\"https://open.spotify.com/embed/episode/3Btf8cRomrl04rpeIqCDpY?utm_source=generator\" width=\"100%\" height=\"352\" frameborder=\"0\" allowfullscreen=\"\" allow=\"autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture\" loading=\"lazy\"></iframe></figure></div>\n                        </div></div>\n                </div>\n            </div>\n            \n        <div class=\"uk-width-2-3@m uk-position-relative\">\n    <div class=\"grid-inner\">\n        <div class=\"uk-sortable\">\n            <div class=\"content-block\">\n                            <div class=\"content-block-inner\"><h1>{%title%}</h1></div>\n                        </div><div class=\"uk-width-1-1 content-block\">\n    <div class=\"content-block-inner\"><h2>This is a very useful podcast exploring the importance of integrating psychedelic and expanded states of awareness. Integration is often used as a general term for what happens after a deep experiential process but what does it actually mean?</h2>\n<p>﻿This is a great podcast to listen to for those attending our <a href=\"https://melbournebreathwork.com/\" target=\"_blank\">Holotropic Breathwork workshops at Melbourne Breathwork</a> or for anyone looking for <a href=\"https://melbourneprocesswork.com/psychedelic-integration\">help with integrating their psychedelic experiences</a>.</p></div>\n</div><div class=\"content-block\">\n                <div class=\"content-block-inner\"><p></p></div>\n            </div>\n        </div>\n    </div>\n</div></div>\n    </div>\n    <div class=\"content-row-overlay\"></div>\n</div>', '2020-11-18 06:52:00', NULL, 0, '1', 'https://www.thewayofthepsychonaut.com/', 'kaleidoscope-2-psychedelic_knvipv', 1042, 1, 'This is a very useful podcast exploring the importance of integrating psychedelic and expanded states of awareness. Integration is often used as a general term for what happens after a deep experiential process but what does it actually mean?', 'Psychedelic Integration - Podcast by Tomas Frymann | Melbourne Breathwork', NULL, 'Explore the importance of psychedelic integration with Tomas Frymann. Ideal for those attending our Holotropic Breathwork workshops or anyone seeking help integrating their psychedelic experiences.', '2025-07-04 07:46:54', '2026-01-05 00:10:29', 4, NULL, 28, NULL, 0, 37, NULL, 0, ''),
